   157→        self.as_specific().deparent_children();
   158→    }
   159→
   160→    pub(crate) fn parent_stylesheet(&self) -> &CSSStyleSheet {
   161→        &self.parent_stylesheet
   162→    }
   163→
   164→    pub(crate) fn shared_lock(&self) -> &SharedRwLock {
   165→        self.parent_stylesheet.shared_lock()
   166→    }
   167→
   168→    pub(crate) fn update_rule(&self, style_rule: &StyleCssRule, guard: &SharedRwLockReadGuard) {
