   249→    /// <https://drafts.csswg.org/cssom/#dom-cssrule-parentstylesheet>
   250→    fn GetParentStyleSheet(&self) -> Option<DomRoot<CSSStyleSheet>> {
   251→        if self.parent_stylesheet_removed.get() {
   252→            None
   253→        } else {
   254→            Some(DomRoot::from_ref(&*self.parent_stylesheet))
   255→        }
   256→    }
