    22→#[dom_struct]
    23→pub(crate) struct CSSSupportsRule {
    24→    cssconditionrule: CSSConditionRule,
    25→    #[ignore_malloc_size_of = "Stylo"]
    26→    #[no_trace]
    27→    supportsrule: RefCell<Arc<SupportsRule>>,
    28→}
    29→
    30→impl CSSSupportsRule {
    31→    fn new_inherited(
    32→        parent_stylesheet: &CSSStyleSheet,
    33→        supportsrule: Arc<SupportsRule>,
    34→    ) -> CSSSupportsRule {
    35→        let list = supportsrule.rules.clone();
    36→        CSSSupportsRule {
    37→            cssconditionrule: CSSConditionRule::new_inherited(parent_stylesheet, list),
    38→            supportsrule: RefCell::new(supportsrule),
    39→        }
    40→    }
    41→
    42→    pub(crate) fn new(
    43→        window: &Window,
    44→        parent_stylesheet: &CSSStyleSheet,
    45→        supportsrule: Arc<SupportsRule>,
    46→        can_gc: CanGc,
    47→    ) -> DomRoot<CSSSupportsRule> {
    48→        reflect_dom_object(
    49→            Box::new(CSSSupportsRule::new_inherited(
    50→                parent_stylesheet,
    51→                supportsrule,
    52→            )),
    53→            window,
    54→            can_gc,
    55→        )
